import binascii
import sys
sys.stdout.reconfigure(encoding='utf-8')
# 刷新前的 6b 00 82 包
before_hex = ""

# 刷新后的 6b 00 ab 包
after_hex = "6b00ab000000000008011204086110011204086010241a0131"

before = binascii.unhexlify(before_hex)
after = binascii.unhexlify(after_hex)

# 搜索 varint: 264 = 0x8802, 240 = 0xf001
print("=== 搜索 88 02 (264) ===")
for i in range(len(before)-1):
    if before[i] == 0x88 and before[i+1] == 0x02:
        print(f"  before 位置 {i}: {before[i-2:i+6].hex()}")

print("\n=== 搜索 f0 01 (240) ===")
for i in range(len(before)-1):
    if before[i] == 0xf0 and before[i+1] == 0x01:
        print(f"  before 位置 {i}: {before[i-2:i+6].hex()}")

for i in range(len(after)-1):
    if after[i] == 0xf0 and after[i+1] == 0x01:
        print(f"  after 位置 {i}: {after[i-2:i+6].hex()}")

print("\n=== after包全部内容 ===")
print(after.hex())